/* Check for sensor timeout - go to safe vent-open state */
 if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
     input.kind == CONTROLLER_INPUT_INVALID_PRESSURE ||
     input.kind == CONTROLLER_INPUT_INVALID_DOOR) {
     controller->has_valid_pressure = false;
     controller->has_valid_door = false;
     controller_set_safe_vent(controller);
     output.compressor_on = controller->compressor_on;
     output.vent_open = controller->vent_open;
     output.state = controller->state;
     output.state_name = controller_state_name(controller->state);
     output.changed =
         (previous_compressor_on != controller->compressor_on) ||
         (previous_vent_open != controller->vent_open) ||
         (previous_state != controller->state);
     return output;
 }

 /* Check for stale sensors - go to safe vent-open state */
 if (input.now_ms > 0U) {
     uint32_t pressure_age = (controller->has_valid_pressure) ?
         (input.now_ms - controller->last_pressure_ms) : input.now_ms;
     uint32_t door_age = (controller->has_valid_door) ?
         (input.now_ms - controller->last_door_ms) : input.now_ms;

     if (pressure_age > CONTROLLER_SENSOR_TIMEOUT_MS ||
         door_age > CONTROLLER_SENSOR_TIMEOUT_MS) {
         controller->has_valid_pressure = false;
         controller->has_valid_door = false;
         controller_set_safe_vent(controller);
         output.compressor_on = controller->compressor_on;
         output.vent_open = controller->vent_open;
         output.state = controller->state;
         output.state_name = controller_state_name(controller->state);
         output.changed =
             (previous_compressor_on != controller->compressor_on) ||
             (previous_vent_open != controller->vent_open) ||
             (previous_state != controller->state);
         return output;
     }
 }

 /* Process input and update sensor state */
 switch (input.kind) {
 case CONTROLLER_INPUT_PRESSURE:
     controller->has_valid_pressure = true;
     controller->last_pressure_kpa = input.pressure_kpa;
     controller->last_pressure_ms = input.now_ms;
     break;
 case CONTROLLER_INPUT_DOOR_OPEN:
     controller->has_valid_door = true;
     controller->door_closed = false;
     controller->last_door_ms = input.now_ms;
     break;
 case CONTROLLER_INPUT_DOOR_CLOSED:
     controller->has_valid_door = true;
     controller->door_closed = true;
     controller->last_door_ms = input.now_ms;
     break;
 case CONTROLLER_INPUT_NONE:
 default:
     /* No new input - keep existing state, but check timeout above */
     break;
 }

 /* Apply control policy based on current sensor state */
 if (!controller->has_valid_pressure || !controller->has_valid_door) {
     /* Need both sensors valid before leaving safe vent-open */
     controller_set_safe_vent(controller);
 } else if (!controller->door_closed) {
     /* Door is open - always go to safe vent-open */
     controller_set_safe_vent(controller);
 } else {
     /* Door is closed and both sensors are valid - apply pressure-based control */
     int pressure = controller->last_pressure_kpa;

     if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
         /* Pressure below 40 kPa - pressurize */
         controller->compressor_on = true;
         controller->vent_open = false;
         controller->state = CONTROLLER_STATE_PRESSURIZING;
     } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
         /* Pressure above 60 kPa - relieve */
         controller->compressor_on = false;
         controller->vent_open = true;
         controller->state = CONTROLLER_STATE_RELIEVING;
     } else {
         /* Pressure in band [40, 60] - hold previous state */
         controller->state = CONTROLLER_STATE_HOLDING;
         /* compressor_on and vent_open unchanged */
     }
 }

 output.compressor_on = controller->compressor_on;
 output.vent_open = controller->vent_open;
 output.state = controller->state;
